var data = msg.payload;
var pompeId = data.pompe_id;

// Stocker dans le contexte flow
var predictions = flow.get('ml_predictions') || {};
predictions[pompeId] = data;
flow.set('ml_predictions', predictions);

// === SORTIE 1 : Gauge anomalie ===
var scoreAnomalie = 0;
var estAnomalie = false;
if (data.isolation_forest) {
    scoreAnomalie = data.isolation_forest.score_anomalie * 100;
    estAnomalie = data.isolation_forest.est_anomalie;
}

var msg1 = {
    payload: Math.round(scoreAnomalie),
    topic: 'Pompe ' + pompeId
};

// === SORTIE 2 : RUL predit par LSTM ===
var rulText = 'Stable';
var rul = -1;
if (data.lstm) {
    rul = data.lstm.rul_minutes;
    if (rul === 0) rulText = 'CRITIQUE!';
    else if (rul > 0 && rul < 60) rulText = rul + ' min';
    else if (rul >= 60) rulText = Math.floor(rul/60) + 'h' + (rul%60) + 'min';
    else rulText = 'Stable';
}

var msg2 = {
    payload: 'P' + pompeId + ' (ML): ' + rulText,
    topic: 'Pompe ' + pompeId
};

// === SORTIE 3 : Alerte ML ===
var msg3 = null;
if (data.niveau_ml === 'ALERTE' || data.niveau_ml === 'CRITIQUE') {
    var alerteMsg = 'ML POMPE ' + pompeId + ' - ' + data.niveau_ml;
    alerteMsg += ' | Score anomalie: ' + (scoreAnomalie).toFixed(0) + '%';
    if (data.lstm) {
        alerteMsg += ' | Delta T predit: ' + data.lstm.delta_t_predit + ' C';
        alerteMsg += ' | RUL: ' + rulText;
    }
    msg3 = {
        payload: alerteMsg,
        topic: 'Alerte ML'
    };
}

// === SORTIE 4 : InfluxDB ===
var msg4 = {
    measurement: 'ml_predictions',
    payload: {
        score_anomalie: scoreAnomalie / 100,
        est_anomalie: estAnomalie ? 1 : 0,
        delta_t_predit: data.lstm ? data.lstm.delta_t_predit : null,
        health_predit: data.lstm ? data.lstm.health_predit : null,
        rul_predit: (data.lstm && data.lstm.rul_minutes >= 0) ? data.lstm.rul_minutes : null,
        tendance: data.lstm ? data.lstm.tendance : 0,
        confiance: data.confiance || 0
    },
    tags: {
        pompe_id: 'pompe_' + pompeId,
        niveau_ml: data.niveau_ml || 'NORMAL'
    }
};

// === SORTIE 5 : Texte resume pour dashboard ===
var resume = 'P' + pompeId + ': ';
resume += data.niveau_ml || 'NORMAL';
if (data.lstm) {
    resume += ' | Predit: ' + data.lstm.delta_t_predit + ' C';
    resume += ' | Health: ' + data.lstm.health_predit + '/100';
}

var msg5 = {
    payload: resume,
    topic: 'Pompe ' + pompeId
};

return [msg1, msg2, msg3, msg4, msg5];

var predictions = flow.get('ml_predictions') || {};

var resultat = {};
for (var id in predictions) {
    var p = predictions[id];
    resultat['pompe_' + id] = {
        niveau_ml: p.niveau_ml || 'NORMAL',
        score_anomalie: p.isolation_forest ? p.isolation_forest.score_anomalie : 0,
        est_anomalie: p.isolation_forest ? p.isolation_forest.est_anomalie : false,
        delta_t_predit: p.lstm ? p.lstm.delta_t_predit : null,
        health_predit: p.lstm ? p.lstm.health_predit : null,
        rul_predit: p.lstm ? p.lstm.rul_minutes : null,
        tendance: p.lstm ? p.lstm.tendance : 0,
        confiance: p.confiance || 0,
        timestamp: p.timestamp || null
    };
}

msg.payload = {
    status: 'ok',
    ml_active: Object.keys(predictions).length > 0,
    nb_pompes: Object.keys(resultat).length,
    predictions: resultat
};

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*'
};

return msg;
